class MovingAverage {
    private int[] window;
    private int size, count = 0, head = 0;
    private long sum = 0;

    public MovingAverage(int size) {
        this.size = size;
        this.window = new int[size];
    }

    public double next(int val) {
        sum -= window[head];   // evict oldest
        window[head] = val;
        sum += val;
        head = (head + 1) % size;
        count++;
        return (double) sum / Math.min(count, size);
    }
}

